mapper.insert:
INSERT INTO PAYMENT (
    user_id, user_name, membership_id, mp_id, gym_id, trainer_id,
    payment_date, payment_price, payment_fee, method, status, payment_type
) VALUES (
    #{userId}, #{userName}, #{membershipId}, #{mpId}, #{gymId}, #{trainerId},
    NOW(), #{paymentPrice}, #{paymentFee}, #{method}, #{status}, #{paymentType}
)

mapper.update:
UPDATE PAYMENT
SET status      = '취소완료',
    canceled_at = NOW(),
    reason      = #{reason}
WHERE id = #{id}

UPDATE PAYMENT
SET status = '환불요청',
    reason = #{reason}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM PAYMENT
WHERE trainer_id   = #{trainerId}
  AND payment_type = 'PT'

  AND DATE(payment_date) >= #{dateFrom}


  AND DATE(payment_date) <= #{dateTo}

SELECT user_name AS clientName, DATE_FORMAT(payment_date, '%Y-%m-%d') AS paymentDate, DATE_FORMAT(payment_date, '%H:%i') AS paymentTime, payment_price AS price, payment_fee AS platformFee, (payment_price - payment_fee) AS netAmount, method, status FROM PAYMENT WHERE trainer_id = #{trainerId} AND payment_type = 'PT'
AND DATE(payment_date) >= #{dateFrom}
AND DATE(payment_date) <= #{dateTo}
ORDER BY
clientName price netAmount status payment_date
${sortDir} LIMIT #{limit} OFFSET #{offset}
